import { a11y, page, render } from "#test/browser"
import { Box } from "./box"

describe("<Box />", () => {
  test("renders component correctly", async () => {
    await a11y(<Box>Box</Box>)
  })

  test("renders HTML tag correctly", async () => {
    await render(<Box>Box</Box>)

    expect(page.getByText("Box").element().tagName).toBe("DIV")
  })
})

"use client"

import type { HTMLStyledProps } from "@yamada-ui/react"
import { styled } from "@yamada-ui/react"

export interface BoxProps extends HTMLStyledProps {}

/**
 * `Box` is the most abstract component on which all other components are built. By default, it renders a `div` element.
 *
 * @see https://yamada-ui.com/docs/components/box
 */
export const Box = styled("div")
